#!/bin/bash
# ============================================
# feishu-bridge 一键部署脚本（自包含，无需 GitHub）
# 在腾讯云 WebShell 中执行: bash deploy-feishu-bridge.sh
# ============================================
set -e
RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'; NC='\033[0m'
echo -e "${GREEN}========================================${NC}"
echo -e "${GREEN}  feishu-bridge 自包含部署${NC}"
echo -e "${GREEN}========================================${NC}"

INSTALL_DIR="/opt/feishu-bridge"
mkdir -p "$INSTALL_DIR" && cd "$INSTALL_DIR"

echo -e "[1/9] 写入文件..."
echo '' | base64 -d > server.js
echo '' | base64 -d > package.json
echo '' | base64 -d > .env.example
echo 'IyDpo57kuaYgR2F0ZXdheSDmoaXmjqXmnI3liqEgRG9ja2VyZmlsZQpGUk9NIG5vZGU6MjItYWxwaW5lCgpXT1JLRElSIC9hcHAKCkNPUFkgcGFja2FnZSouanNvbiAuLwpSVU4gbnBtIGluc3RhbGwgLS1wcm9kdWN0aW9uCgpDT1BZIC4gLgoKRVhQT1NFIDMwMDAKCkNNRCBbIm5vZGUiLCAic2VydmVyLmpzIl0K' | base64 -d > Dockerfile
echo '' | base64 -d > deploy.sh
echo '' | base64 -d > feishu-bridge.service
echo '' | base64 -d > README.md
echo 'bm9kZV9tb2R1bGVzLwouZW52CioubG9nCi5EU19TdG9yZQo=' | base64 -d > .gitignore

echo -e "${GREEN}文件写入完成 ✓${NC}"

# 检查 Node.js
echo -e "\n${YELLOW}[2/9] 检查 Node.js...${NC}"
if ! command -v node &>/dev/null; then
  echo -e "${RED}未检测到 Node.js，正在安装...${NC}"
  curl -o- https://raw.githubusercontent.com/nvm-sh/nvm/v0.39.7/install.sh | bash
  export NVM_DIR="$HOME/.nvm"
  [ -s "$NVM_DIR/nvm.sh" ] && . "$NVM_DIR/nvm.sh"
  nvm install 22
fi
echo "Node.js $(node -v) ✓"

# 安装依赖
echo -e "\n${YELLOW}[3/9] 安装依赖...${NC}"
npm install --production
echo -e "${GREEN}依赖安装完成 ✓${NC}"

# 配置 .env
echo -e "\n${YELLOW}[4/9] 检查配置...${NC}"
if [ ! -f .env ]; then
  cp .env.example .env
  echo -e "${RED}⚠ 请编辑 /opt/feishu-bridge/.env 填入真实配置！${NC}"
  echo "  vim /opt/feishu-bridge/.env"
fi

# 安装 PM2
echo -e "\n${YELLOW}[5/9] 检查 PM2...${NC}"
if ! command -v pm2 &>/dev/null; then
  npm install -g pm2
fi
echo "PM2 ✓"

# 启动服务
echo -e "\n${YELLOW}[6/9] 启动服务...${NC}"
pm2 delete feishu-bridge 2>/dev/null || true
pm2 start server.js --name feishu-bridge
pm2 save 2>/dev/null || true

# 设置开机自启
echo -e "\n${YELLOW}[7/9] 设置开机自启...${NC}"
pm2 startup 2>/dev/null || true

# 状态
echo -e "\n${YELLOW}[8/9] 服务状态...${NC}"
pm2 status feishu-bridge

echo -e "\n${YELLOW}[9/9] 完成${NC}"
echo -e "${GREEN}========================================${NC}"
echo -e "${GREEN}  部署完成！${NC}"
echo -e "${GREEN}========================================${NC}"
echo ""
echo "查看日志: pm2 logs feishu-bridge"
echo "重启服务: pm2 restart feishu-bridge"
echo "编辑配置: vim /opt/feishu-bridge/.env"
echo ""
echo "⚠ 下一步："
echo "  1. 编辑 .env 填入 FEISHU_APP_SECRET 和 FEISHU_VERIFICATION_TOKEN"
echo "  2. 腾讯云安全组开放端口 3000"
echo "  3. 飞书后台配置事件订阅: http://<服务器IP>:3000/feishu/callback"
